/**
 * Returns the vendor count, top vendors, locality counts, and category
counts for the given city slug. Used by /:city programmatic landing
pages so the page can render link rails and JSON-LD without N+1 calls.

 * @summary Aggregated counts for a city landing page
 */
export const GetCitySummaryParams = zod.object({
  "citySlug": zod.coerce.string()
}).strict()

export const GetCitySummaryResponse = zod.object({
  "citySlug": zod.string(),
  "canonicalCity": zod.string(),
  "vendorCount": zod.number(),
  "localityCounts": zod.array(zod.object({
  "slug": zod.string(),
  "name": zod.string(),
  "count": zod.number()
})),
  "categoryCounts": zod.array(zod.object({
  "slug": zod.string(),
  "count": zod.number()
})),
  "topVendors": zod.array(zod.object({
  "id": zod.number(),
  "businessName": zod.string(),
  "category": zod.string(),
  "city": zod.string().nullish(),
  "state": zod.string().nullish(),
  "address": zod.string().nullish(),
  "bannerImage": zod.string(),
  "rating": zod.number(),
  "reviewCount": zod.number()
}))
})


/**
 * @summary Aggregated pubs for a city/locality landing page
 */
export const GetLocalitySummaryParams = zod.object({
  "citySlug": zod.coerce.string(),
  "localitySlug": zod.coerce.string()
}).strict()

export const GetLocalitySummaryResponse = zod.object({
  "citySlug": zod.string(),
  "canonicalCity": zod.string(),
  "localitySlug": zod.string(),
  "localityName": zod.string(),
  "vendorCount": zod.number(),
  "topVendors": zod.array(zod.object({
  "id": zod.number(),
  "businessName": zod.string(),
  "category": zod.string(),
  "city": zod.string().nullish(),
  "state": zod.string().nullish(),
  "address": zod.string().nullish(),
  "bannerImage": zod.string(),
  "rating": zod.number(),
  "reviewCount": zod.number()
}))
})


/**
 * @summary Aggregated pubs for a city/category landing page
 */
export const GetCategorySummaryParams = zod.object({
  "citySlug": zod.coerce.string(),
  "categorySlug": zod.enum(['rooftop', 'microbrewery', 'sports-bar', 'live-music', 'couple-friendly', 'lounge', 'club', 'pubs'])
}).strict()

export const GetCategorySummaryResponse = zod.object({
  "citySlug": zod.string(),
  "canonicalCity": zod.string(),
  "categorySlug": zod.string(),
  "vendorCount": zod.number(),
  "topVendors": zod.array(zod.object({
  "id": zod.number(),
  "businessName": zod.string(),
  "category": zod.string(),
  "city": zod.string().nullish(),
  "state": zod.string().nullish(),
  "address": zod.string().nullish(),
  "bannerImage": zod.string(),
  "rating": zod.number(),
  "reviewCount": zod.number()
}))
})


